package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader);
    }

    @Test
    void testRead_withNewLineIncrementsLineCounterAndSetsLastChar() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        // Mock super.read() to return '\n'
        doReturn('\n').when(spyReader).read();

        // We need to call the real read method of ExtendedBufferedReader, not the spy one to avoid recursion
        // So we mock super.read() by spying on BufferedReader and delegate ExtendedBufferedReader.read to call super.read()
        // But since ExtendedBufferedReader extends BufferedReader, and super.read() is called in ExtendedBufferedReader.read,
        // we need to mock the BufferedReader.read() method that ExtendedBufferedReader calls.

        // To do this, create a spy on ExtendedBufferedReader and mock BufferedReader.read() by creating a partial mock with a Reader
        // Instead, we can create a subclass to override BufferedReader.read() or use reflection to set lastChar and lineCounter.
        // But the simplest way is to create a spy on ExtendedBufferedReader and mock super.read() call by mocking BufferedReader.read().

        // So we create a spy on ExtendedBufferedReader with a dummy Reader that returns '\n' on read()
        Reader reader = new Reader() {
            boolean returnedNewLine = false;
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                return -1;
            }
            @Override
            public int read() throws IOException {
                if (!returnedNewLine) {
                    returnedNewLine = true;
                    return '\n';
                }
                return -1;
            }
            @Override
            public void close() throws IOException {}
        };
        ExtendedBufferedReader ebr = new ExtendedBufferedReader(reader);

        int result = ebr.read();

        assertEquals('\n', result);
        // lineCounter should be incremented to 1
        int lineNumber = getLineCounter(ebr);
        assertEquals(1, lineNumber);
        int lastChar = getLastChar(ebr);
        assertEquals('\n', lastChar);
    }

    @Test
    void testRead_withNonNewLineSetsLastCharButDoesNotIncrementLineCounter() throws IOException {
        Reader reader = new Reader() {
            private int count = 0;
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                return -1;
            }
            @Override
            public int read() throws IOException {
                if (count == 0) {
                    count++;
                    return 'a';
                }
                return -1;
            }
            @Override
            public void close() throws IOException {}
        };
        ExtendedBufferedReader ebr = new ExtendedBufferedReader(reader);

        int result = ebr.read();

        assertEquals('a', result);
        int lineNumber = getLineCounter(ebr);
        assertEquals(0, lineNumber);
        int lastChar = getLastChar(ebr);
        assertEquals('a', lastChar);
    }

    @Test
    void testRead_withEndOfStreamSetsLastCharToEndOfStream() throws IOException {
        Reader reader = new Reader() {
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                return -1;
            }
            @Override
            public int read() throws IOException {
                return -1;
            }
            @Override
            public void close() throws IOException {}
        };
        ExtendedBufferedReader ebr = new ExtendedBufferedReader(reader);

        int result = ebr.read();

        assertEquals(-1, result);
        int lineNumber = getLineCounter(ebr);
        assertEquals(0, lineNumber);
        int lastChar = getLastChar(ebr);
        assertEquals(-1, lastChar);
    }

    private int getLineCounter(ExtendedBufferedReader ebr) {
        try {
            java.lang.reflect.Field field = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
            field.setAccessible(true);
            return (int) field.get(ebr);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private int getLastChar(ExtendedBufferedReader ebr) {
        try {
            java.lang.reflect.Field field = ExtendedBufferedReader.class.getDeclaredField("lastChar");
            field.setAccessible(true);
            return (int) field.get(ebr);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
